  createNode(nodes, mediaId, rootId, "Importing Media", "Add photos, videos, audio, PDFs, and other files to your content using the Import File button (paperclip icon) in the toolbar, or by dragging files directly into the content pane. The file type is auto-detected: images embed as viewable photos, videos embed with playback controls, audio files embed with a native audio player, PDFs offer a choice to extract text or insert as a download link, and other files are inserted as download links. Media is saved with your outline.", []);
  createNode(nodes, photoId, mediaId, "Photos & Images", "Insert images from your device:\n\n1. Click the Import File button (paperclip icon) in the toolbar\n2. Choose an image file (JPEG, PNG, etc.)\n\nOr simply drag and drop an image file into the content pane.\n\nYou can also **paste images directly from your clipboard** (Cmd+V / Ctrl+V). This works with screenshots, images copied from websites, or any image on your clipboard.\n\nImages are stored directly in your outline - no external hosting needed.");
  createNode(nodes, videoId, mediaId, "Video Files", "Insert video files from your device:\n\n1. Click the Import File button (paperclip icon) in the toolbar\n2. Choose a video file (MP4, MOV, etc.)\n\nVideos include full playback controls (play, pause, seek, volume). Note: Large videos increase outline file size.");
  createNode(nodes, audioId, mediaId, "Audio Files", "Insert audio files from your device:\n\n1. Click the Import File button (paperclip icon) in the toolbar\n2. Choose an audio file (MP3, WAV, AAC, etc.)\n\nAudio files embed with a native audio player that includes play, pause, seek, and volume controls. You can also drag and drop audio files or paste them from your clipboard.");
  createNode(nodes, youtubeId, mediaId, "YouTube Videos", "Embed YouTube videos that stream directly:\n\n1. Click the + (Insert) menu > 'YouTube Video'\n2. Paste any YouTube URL\n3. The video embeds with full playback controls\n\nYouTube videos stream from YouTube's servers - they don't increase your outline size.");
  createNode(nodes, pdfId, mediaId, "PDF Documents", "Import PDF files from your device:\n\n1. Click the Import File button (paperclip icon) in the toolbar\n2. Choose a PDF file\n3. A dialog appears with two options:\n   - **Extract Document**: Uses AI to extract and format the PDF content with preserved headings, lists, and structure\n   - **Insert as Link**: Inserts a clickable download link for the PDF\n\nYou can also drag and drop PDF files into the content pane.");
  createNode(nodes, drawingId, mediaId, "Drawings & Sketches", "Create freehand drawings:\n\n1. Click the + (Insert) menu > 'Drawing'\n2. Use the drawing canvas to sketch\n3. Click 'Insert' to add to your content\n\nDrawings are saved as images in your outline.");
  createNode(nodes, fullscreenId, mediaId, "Fullscreen Viewing", "Double-click any image, video, or diagram to view it fullscreen. This is especially useful for:\n\n- Reading details in photos\n- Viewing diagrams at full size\n- Watching videos without distraction\n\nClick outside the content or press the X button to close fullscreen view.");

