  const sidebarSearchId = uuidv4();

  createNode(nodes, sidebarMultiSelectId, advancedId, "Sidebar Multi-Select & Bulk Delete", "You can select multiple outlines in the sidebar and delete them in one step.\n\n**Selecting outlines (desktop):**\n- **Cmd/Ctrl + Click** an outline to toggle it in/out of selection\n- **Shift + Click** to select a range of outlines between the current and clicked outline\n\n**Selecting outlines (mobile / touch):**\n- **Long-press** any outline in the mobile sidebar sheet to enter select mode (the first long-pressed outline becomes selected)\n- Once in select mode, **tap** other outlines to add or remove them from the selection\n- A bar at the top shows \"X selected\" along with **Cancel** (exit select mode) and **Delete** buttons\n\n**Renaming outlines:**\n- **Desktop:** Right-click an outline (or hover and use the ⋯ menu) and choose Rename\n- **Mobile:** Tap the ⋯ icon on the right of any outline row and choose Rename — an inline text field appears; Enter saves, Escape cancels\n\n**Bulk action bar:**\nWhen outlines are selected, a bar appears showing the count (e.g., \"3 selected\") along with Clear/Cancel and Delete buttons.\n- **Clear / Cancel** deselects all outlines and exits select mode\n- **Delete** opens a single confirmation dialog for the entire batch\n\n**Note:** The delete confirmation setting in Settings applies to both node deletion and outline deletion. If you have turned off confirmations, bulk delete will proceed immediately.");

  createNode(nodes, sidebarSearchId, advancedId, "Sidebar Search", "Quickly find outlines by name using the search field in the sidebar.\n\n**How to use:**\n1. Type in the search field below the Outlines header\n2. The list filters in real time to show only matching outlines\n3. The count updates to show matches vs total (e.g., \"5 / 42\")\n4. Click the X button or clear the text to show all outlines again\n\n**Details:**\n- Search is case-insensitive\n- The User Guide is also filtered by search\n- Available in both the desktop sidebar and the mobile sidebar sheet\n- On mobile, the search clears automatically when you select an outline");

  // === MCP SERVER (API ACCESS) ===
  const mcpId = uuidv4();
